={
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "You are an expert ATS (Applicant Tracking System) optimizer and professional resume writer. You will receive candidate profile data (source_profile.json) and a job_description.\n\nSTRICT CONSTRAINTS:\n- NEVER invent, fabricate, or exaggerate work experience, metrics, companies, titles, or dates.\n- You may ONLY reorder, highlight, or rephrase bullet points from source_profile.json to emphasize relevance to the target job.\n- Align technical terminology with keywords from the job description where factually accurate.\n- Output MUST strictly adhere to the requested JSON structure. Output raw JSON ONLY."
    },
    {
      "role": "user",
      "content": "Source Profile:\n{{ JSON.stringify(require('./source_profile.json')) }}\n\nTarget Job Description:\n{{ $('Stage 1: Job Discovery Webhook').item.json.description }}"
    }
  ],
  "temperature": 0.2,
  "response_format": { "type": "json_object" },
  "stream": false
}

={
  "username": "JobApply AI Assistant",
  "embeds": [
    {
      "title": "🎯 New Matching Job Application Found!",
      "color": 3066993,
      "fields": [
        {
          "name": "🏢 Company",
          "value": "{{ $('Stage 1: Job Discovery Webhook').item.json.company }}",
          "inline": true
        },
        {
          "name": "💼 Title",
          "value": "{{ $('Stage 1: Job Discovery Webhook').item.json.title }}",
          "inline": true
        },
        {
          "name": "📊 Match Score",
          "value": "**{{ JSON.parse($('Stage 2: Evaluation Gate (Python)').item.json.stdout).score }}%**",
          "inline": true
        },
        {
          "name": "🔗 Apply URL",
          "value": "{{ $('Stage 1: Job Discovery Webhook').item.json.apply_url }}",
          "inline": false
        },
        {
          "name": "📄 Tailored Resume PDF",
          "value": "`output_resumes/{{ $('Stage 1: Job Discovery Webhook').item.json.job_id }}_Resume.pdf`",
          "inline": false
        }
      ]
    }
  ]
}
